"""
codebench_repl — persistent-namespace REPL for CodeBench
═══════════════════════════════════════════════════════

A `>>>` REPL that:
  • Preserves namespace across invocations within a session
  • Pretty-prints DataFrames / ndarrays / images using
    `codebench_inline.display()` so they render in the output panel
  • Tab-completion via `rlcompleter` (already enabled when readline
    is available, which the iOS bundle exposes via gnureadline)
  • Catches KeyboardInterrupt cleanly so Ctrl-C just gets you back
    to the prompt without killing the REPL

Used as a shell builtin:
    repl              ← drop into the REPL with a fresh namespace
    repl --keep       ← drop into the REPL preserving the previous one
    repl <file.py>    ← execfile <file.py> first, then drop in

Inside the REPL:
    :q                ← exit back to the shell
    :clear            ← reset the namespace
    :show             ← list all variables currently defined
    :save FILE        ← save the current REPL transcript to FILE

Any bare statement starting with `:` is treated as a meta-command, so
slicing syntax like `a[:5]` still works.
"""

import code
import sys
import traceback
import textwrap
from typing import Any, Dict, Optional


# ── Persistent namespace ─────────────────────────────────────────
# Module-level dict survives multiple `repl` invocations in the same
# session, so the user can drop out, tweak a script, run it, then
# re-enter the REPL with everything still in scope.
_NAMESPACE: Dict[str, Any] = {}
_TRANSCRIPT: list = []


def _build_initial_ns() -> Dict[str, Any]:
    """Seed namespace with the same convenience names that scripts get."""
    ns: Dict[str, Any] = {"__name__": "__codebench_repl__"}
    # Common stdlib (mirror offlinai_shell._convenience_globals)
    try:
        import math, os, sys as _sys, json, re, time, datetime, pathlib
        from collections import (defaultdict, Counter, OrderedDict, deque)
        from itertools import chain, combinations, permutations, product
        from functools import partial, reduce, lru_cache
        ns.update({
            'math': math, 'os': os, 'sys': _sys, 'json': json, 're': re,
            'time': time, 'datetime': datetime, 'pathlib': pathlib,
            'defaultdict': defaultdict, 'Counter': Counter,
            'OrderedDict': OrderedDict, 'deque': deque,
            'chain': chain, 'combinations': combinations,
            'permutations': permutations, 'product': product,
            'partial': partial, 'reduce': reduce, 'lru_cache': lru_cache,
            'Path': pathlib.Path,
        })
    except Exception:
        pass
    # Optional: data-science quick imports
    for mod_name, alias in [
        ('numpy', 'np'), ('pandas', 'pd'), ('matplotlib.pyplot', 'plt'),
    ]:
        try:
            mod = __import__(mod_name, fromlist=['*'] if '.' in mod_name else [])
            ns[alias] = mod
        except ImportError:
            pass
    # Inline display helper
    try:
        from codebench_inline import display, show_html, show_png
        ns['display'] = display
        ns['show_html'] = show_html
        ns['show_png'] = show_png
        # Also install the auto-show hooks
        import codebench_inline
        codebench_inline.install()
    except Exception:
        pass
    return ns


def _is_meta(line: str) -> bool:
    """`:q`, `:clear`, etc. (not `a[:5]`)."""
    s = line.lstrip()
    if not s.startswith(":"):
        return False
    rest = s[1:].split(None, 1)
    if not rest:
        return False
    return rest[0] in {"q", "quit", "exit", "clear", "show", "save", "help"}


def _handle_meta(line: str, console: code.InteractiveConsole) -> bool:
    """Run a meta-command. Returns True if the caller should keep looping,
    False if the REPL should exit."""
    s = line.lstrip()[1:].strip()
    parts = s.split(None, 1)
    cmd = parts[0]
    arg = parts[1] if len(parts) > 1 else ""
    if cmd in ("q", "quit", "exit"):
        return False
    if cmd == "clear":
        _NAMESPACE.clear()
        _NAMESPACE.update(_build_initial_ns())
        console.locals = _NAMESPACE
        print("namespace cleared")
        return True
    if cmd == "show":
        user = sorted(k for k in _NAMESPACE
                      if not k.startswith("__"))
        if not user:
            print("(empty)")
        else:
            for k in user:
                v = _NAMESPACE[k]
                t = type(v).__name__
                try:
                    rep = repr(v)
                except Exception:
                    rep = "<unrepr-able>"
                if len(rep) > 60:
                    rep = rep[:60] + "…"
                print(f"  {k:<20s} {t:<15s} {rep}")
        return True
    if cmd == "save":
        if not arg:
            print("usage: :save <file>")
            return True
        try:
            with open(arg, "w", encoding="utf-8") as f:
                f.write("\n".join(_TRANSCRIPT))
            print(f"transcript saved to {arg}")
        except OSError as e:
            print(f"could not write: {e}")
        return True
    if cmd == "help":
        print(textwrap.dedent("""
            REPL meta-commands:
              :q  / :quit / :exit   Leave the REPL (namespace persists for next time)
              :clear                Reset namespace
              :show                 List all defined names
              :save FILE            Write transcript to FILE
              :help                 This message
            """).strip())
        return True
    return True


def run_repl(initial_file: Optional[str] = None, keep_namespace: bool = False) -> int:
    """Drop into the REPL. Returns exit status (always 0 unless we
    were re-entered while another REPL was already running)."""
    global _NAMESPACE
    if not keep_namespace or not _NAMESPACE:
        _NAMESPACE = _build_initial_ns()

    # exec the initial file in the namespace, if any
    if initial_file:
        try:
            with open(initial_file, "r", encoding="utf-8") as f:
                src = f.read()
            exec(compile(src, initial_file, "exec"), _NAMESPACE)
            print(f"# Loaded {initial_file}")
        except Exception:
            traceback.print_exc()

    # Build the console
    console = code.InteractiveConsole(locals=_NAMESPACE,
                                      filename="<codebench-repl>")
    # Enable rlcompleter for tab-completion if readline is available
    try:
        import readline, rlcompleter
        readline.set_completer(rlcompleter.Completer(_NAMESPACE).complete)
        readline.parse_and_bind("tab: complete")
    except Exception:
        pass

    print(f"CodeBench REPL — Python {sys.version.split()[0]} "
          f"({len(_NAMESPACE)} names in scope)")
    print("(`:q` to exit, `:help` for meta-commands)")

    buffer: list = []
    more = False
    while True:
        try:
            ps = "... " if more else ">>> "
            line = input(ps)
        except KeyboardInterrupt:
            print("\nKeyboardInterrupt")
            buffer.clear()
            more = False
            continue
        except EOFError:
            print()
            break

        # Meta-command? (only at top level — never inside a multi-line block)
        if not more and _is_meta(line):
            if not _handle_meta(line, console):
                break
            continue

        _TRANSCRIPT.append(line)
        buffer.append(line)
        try:
            more = console.push("\n".join(buffer))
            if not more:
                buffer.clear()
        except KeyboardInterrupt:
            print("\nKeyboardInterrupt")
            buffer.clear()
            more = False
    print("# REPL exited (namespace preserved for next `repl --keep`)")
    return 0


# ─── Auto-display the last expression ────────────────────────────
#
# `code.InteractiveConsole` already does this — `displayhook` is set to
# pretty-print. We patch it lightly to use our `display()` for known
# rich types so DataFrames render as tables, plots inline, etc.

_orig_displayhook = sys.displayhook

def _rich_displayhook(value):
    if value is None:
        return
    # Same heuristic as codebench_inline.display
    try:
        import pandas as pd
        if isinstance(value, (pd.DataFrame, pd.Series)):
            from codebench_inline import display
            display(value)
            __builtins__['_'] = value if isinstance(__builtins__, dict) \
                                       else None
            return
    except Exception:
        pass
    _orig_displayhook(value)


def install_rich_displayhook() -> None:
    """Replace sys.displayhook so REPL results print rich."""
    sys.displayhook = _rich_displayhook
